  "おなか|16": {"jp":"ごはんをたくさん食べて、おなかがいっぱいです。","r":"gohan o takusan tabete, onaka ga ippai desu.","de":"Ich habe viel gegessen und bin satt.","note":"おなかがいっぱい = satt sein."},
  "あし|16": {"jp":"あの人は足が長くて、かっこいいです。","r":"ano hito wa ashi ga nagakute, kakkoii desu.","de":"Diese Person hat lange Beine und sieht gut aus.","note":"足 = Bein/Fuß; 長くて (て-Form)."},
  "サービス|16": {"jp":"このホテルはサービスがいいです。","r":"kono hoteru wa saabisu ga ii desu.","de":"Dieses Hotel hat einen guten Service.","note":"A は B が Adjektiv: サービスがいい."},
  "あんしょうばんごう|16": {"jp":"カードを入れて、暗証番号を押してください。","r":"kaado o irete, anshoo bangoo o oshite kudasai.","de":"Bitte stecken Sie die Karte ein und geben Sie die PIN ein.","note":"暗証番号 = Geheimnummer/PIN."},
  "ボタン|16": {"jp":"このボタンを押して、お金を下ろします。","r":"kono botan o oshite, okane o oroshimasu.","de":"Ich drücke diesen Knopf und hebe Geld ab.","note":"ボタンを押します = einen Knopf drücken."},
  "カード|16": {"jp":"カードを入れてから、ボタンを押します。","r":"kaado o irete kara, botan o oshimasu.","de":"Nachdem ich die Karte eingesteckt habe, drücke ich den Knopf.","note":"～てから für die Reihenfolge."},
  "こうむいん|16": {"jp":"父は公務員で、まじめです。","r":"chichi wa koomuin de, majime desu.","de":"Mein Vater ist Beamter und gewissenhaft.","note":"Nomen で… verbindet wie て-Form."},
  "それから|16": {"jp":"宿題をします。それからテレビを見ます。","r":"shukudai o shimasu. sorekara terebi o mimasu.","de":"Ich mache Hausaufgaben. Danach schaue ich fern.","note":"それから = und danach (Satzanfang)."},
  "どうやって|16": {"jp":"駅までどうやって行きますか。","r":"eki made dooyatte ikimasu ka.","de":"Wie kommt man zum Bahnhof?","note":"どうやって fragt nach dem Weg/der Art."},
  "どの～|16": {"jp":"どの電車に乗りますか。","r":"dono densha ni norimasu ka.","de":"In welchen Zug steigen Sie ein?","note":"どの + Nomen = welcher (von mehreren)."},

  /* Lektion 17 */
  "おぼえます|17": {"jp":"ことばを たくさん おぼえなければ なりません。","r":"kotoba o takusan oboenakereba narimasen.","de":"Ich muss mir viele Vokabeln merken.","note":"おぼえます ist V. II: ない-Form おぼえない."},
