  "かぜ|17": {"jp":"かぜですから、くすりを のまなければ なりません。","r":"kaze desu kara, kusuri o nomanakereba narimasen.","de":"Weil ich erkältet bin, muss ich Medizin nehmen.","note":"かぜ = Erkältung (Nomen)."},
  "ねつ|17": {"jp":"ねつが ありますから、きょうは でかけません。","r":"netsu ga arimasu kara, kyou wa dekakemasen.","de":"Weil ich Fieber habe, gehe ich heute nicht aus.","note":"ねつが あります = Fieber haben."},
  "びょうき|17": {"jp":"びょうきですから、しごとを やすまなければ なりません。","r":"byouki desu kara, shigoto o yasumanakereba narimasen.","de":"Weil ich krank bin, muss ich der Arbeit fernbleiben.","note":"びょうき = Krankheit (Nomen)."},
  "くすり|17": {"jp":"この くすりを のまなくても いいです。","r":"kono kusuri o nomanakutemo ii desu.","de":"Diese Medizin müssen Sie nicht einnehmen.","note":"くすりを のみます = Medizin einnehmen."},
  "[お]ふろ|17": {"jp":"まいばん おふろに はいります。","r":"maiban ofuro ni hairimasu.","de":"Jeden Abend nehme ich ein Bad.","note":"おふろに はいります = baden."},
